//! # touptek-rs â€” safe Rust bindings for the ToupTek ToupCam camera SDK
//!
//! Sibling crate to [`zwo-rs`](https://crates.io/crates/zwo-rs) and
//! [`qhyccd-rs`](https://crates.io/crates/qhyccd-rs). It wraps the raw FFI in
//! `libtoupcam-sys` â€” generated by `bindgen` from the vendored ToupTek SDK header
//! â€” in a safe, ergonomic API. It will be consumed by rusty-photon's
//! `touptek-camera` ASCOM Alpaca driver (see `docs/plans/touptek-driver.md`).
//!
//! The same flat C ABI is shared by every OEM rebrand of the SDK (Altair, Omegon,
//! Meade, Bresser, Mallincam, RisingCam/Ogma, SVBony, StarShootG, Nncam, Tscam)
//! with only the `Toupcam_` symbol prefix swapped.
//!
//! ## Status
//!
//! **Phase E.** Enumeration ([`Sdk::enumerate`]), the [`Camera`] handle, and â€” the
//! centrepiece â€” the **callback â†’ blocking bridge** for pull-mode/trigger exposures
//! ([`Camera::start_pull_mode`] / [`Camera::trigger_single`] /
//! [`Camera::wait_for_event`] / [`Camera::pull_image`]) are wired, plus the
//! ASCOM-driving control surface this crate now owns: gain range/value, black
//! level, exposure range, cooling control ([`Camera::set_cooler`] /
//! [`Camera::cooler_power_percent`] / [`Camera::set_target_temperature_tenths`] /
//! [`Camera::target_temperature_tenths`]),
//! ST4 guiding ([`Camera::st4_pulse_guide`] + [`GuideDirection`]), and the
//! capability flags + sensor geometry on [`CameraInfo`]. The real RAW-pixel-format
//! buffer sizing and per-platform link are finalised against hardware in Phase F.
//!
//! ## `simulation` feature
//!
//! Mirrors zwo-rs/qhyccd-rs: a hardware-free, in-Rust simulated camera for
//! development and tests. As with those, the SDK is still *linked* when the
//! feature is on â€” it removes the hardware, not the link. With the feature on the
//! SDK is never called: enumeration reports [`SIM_CAMERA_COUNT`] and the camera
//! fabricates frames.
//!
//! ## Build requirements
//!
//! - **libclang** â€” `libtoupcam-sys` runs `bindgen` at build time (needed for
//!   `check`/`clippy`/build; *not* the SDK).
//! - **The ToupTek SDK** (`libtoupcam`) on the link path â€” needed to *link* (i.e.
//!   `build`/`test` a binary), even with the `simulation` feature, unless
//!   `TOUPCAM_SKIP_NATIVE_LINK=1` is set.

/// Raw, unsafe FFI bindings (`bindgen`). Prefer the safe API in this crate.
pub use libtoupcam_sys as sys;

mod camera;
mod error;
#[cfg(not(feature = "simulation"))]
mod ffi_util;

pub use camera::{Camera, CameraInfo, Event, Frame, GuideDirection};
pub use error::{hr_check, Error, Result, SdkError};

/// Number of simulated cameras presented when the `simulation` feature is on.
#[cfg(feature = "simulation")]
pub const SIM_CAMERA_COUNT: usize = 1;

/// Entry point to the ToupTek SDK.
///
/// Enumerates connected cameras and opens them. With the `simulation` feature, a
/// fixed simulated camera is reported and the native SDK is never called (though
/// it is still linked â€” see the crate docs).
#[derive(Debug, Default)]
pub struct Sdk {
    _private: (),
}

impl Sdk {
    /// Initialise the SDK.
    ///
    /// # Errors
    /// Currently infallible, but returns [`Result`] so future initialisation can
    /// surface failures without an API break.
    pub fn new() -> Result<Self> {
        tracing::debug!("initialising ToupTek SDK");
        Ok(Self { _private: () })
    }

    /// Number of connected cameras.
    ///
    /// # Errors
    /// Propagates an enumeration failure on the real path; infallible under
    /// `simulation`.
    pub fn camera_count(&self) -> Result<usize> {
        #[cfg(feature = "simulation")]
        let count = SIM_CAMERA_COUNT;
        #[cfg(not(feature = "simulation"))]
        let count = self.enumerate()?.len();
        Ok(count)
    }

    /// Enumerate connected cameras (`Toupcam_EnumV2`).
    ///
    /// # Errors
    /// Infallible today; returns [`Result`] for forward compatibility (a future
    /// init/version check may fail).
    pub fn enumerate(&self) -> Result<Vec<CameraInfo>> {
        #[cfg(feature = "simulation")]
        {
            // Models the ToupTek ATR533C (Sony IMX533): a 3008Ă—3008 colour 16-bit
            // sensor with 3.76 Âµm pixels, a cooler, and an ST4 port. Real ATR533C
            // hardware has no ST4 port, but the simulator keeps one so the BDD /
            // ConformU suites exercise PulseGuide alongside cooling and the colour
            // (RGGB) path from one device (see `docs/services/touptek-camera.md`).
            // The 3008Â˛ frame (vs the ASI2600-sized 6248Ă—4176 it replaced) keeps
            // ConformU's full-frame ImageArrayVariant serialisation well under its
            // response-timeout watchdog even under parallel-suite load on macOS.
            Ok(vec![CameraInfo {
                id: "sim-0".to_owned(),
                display_name: "Simulated ToupTek Camera".to_owned(),
                model_name: "ToupTek ATR533C (simulated)".to_owned(),
                flag: u64::from(sys::TOUPCAM_FLAG_TEC)
                    | u64::from(sys::TOUPCAM_FLAG_ST4)
                    | u64::from(sys::TOUPCAM_FLAG_BLACKLEVEL),
                pixel_size_x: 3.76,
                pixel_size_y: 3.76,
                max_width: 3008,
                max_height: 3008,
                bit_depth: 16,
                is_color: true,
                supported_bins: vec![1, 2, 3, 4],
            }])
        }
        #[cfg(not(feature = "simulation"))]
        {
            // SAFETY: `arr` is a fixed `TOUPCAM_MAX`-element array of POD structs
            // (zeroed is a valid bit pattern); `Toupcam_EnumV2` fills up to that
            // many entries and returns the count.
            let mut arr: [sys::ToupcamDeviceV2; sys::TOUPCAM_MAX as usize] =
                unsafe { std::mem::zeroed() };
            let count = unsafe { sys::Toupcam_EnumV2(arr.as_mut_ptr()) } as usize;
            let count = count.min(arr.len());
            Ok(arr.iter().take(count).map(device_info).collect())
        }
    }

    /// Open the camera at enumeration `index`.
    ///
    /// # Errors
    /// [`Error::DeviceNotFound`] if no camera is present at `index` or the handle
    /// cannot be opened.
    pub fn open(&self, index: usize) -> Result<Camera> {
        let info = self
            .enumerate()?
            .into_iter()
            .nth(index)
            .ok_or(Error::DeviceNotFound)?;
        Camera::open_by_index(index as u32, info)
    }
}

/// Convert a raw enumerated `ToupcamDeviceV2` (+ its model) into [`CameraInfo`].
#[cfg(not(feature = "simulation"))]
fn device_info(dev: &sys::ToupcamDeviceV2) -> CameraInfo {
    use crate::ffi_util::{c_string_field, c_string_from_ptr};

    let id = c_string_field(&dev.id);
    let display_name = c_string_field(&dev.displayname);
    let (model_name, flag, pixel_size_x, pixel_size_y, max_width, max_height) =
        if dev.model.is_null() {
            (String::new(), 0, 0.0, 0.0, 0, 0)
        } else {
            // SAFETY: `model` points to a static `ToupcamModelV2` owned by the SDK
            // for the lifetime of enumeration; we only read it.
            let model = unsafe { &*dev.model };
            let name = if model.name.is_null() {
                String::new()
            } else {
                // SAFETY: `name` is a static, NUL-terminated SDK-owned string
                // (`char*` off-Windows, `wchar_t*` on Windows â€” see `ffi_util`).
                unsafe { c_string_from_ptr(model.name) }
            };
            // `res[0]` is the full-frame (maximum) resolution.
            let res = model.res[0];
            (
                name,
                model.flag,
                model.xpixsz,
                model.ypixsz,
                res.width,
                res.height,
            )
        };

    CameraInfo {
        id,
        display_name,
        model_name,
        bit_depth: bit_depth_from_flag(flag),
        is_color: flag & u64::from(sys::TOUPCAM_FLAG_MONO) == 0,
        // ToupTek does not enumerate the supported digital-binning factors; the
        // common 1â€“4 set is assumed here and refined against real hardware in
        // Phase F (see `docs/plans/touptek-driver.md`).
        supported_bins: vec![1, 2, 3, 4],
        flag,
        pixel_size_x,
        pixel_size_y,
        max_width,
        max_height,
    }
}

/// The RAW bit depth a model reads, from its `TOUPCAM_FLAG_RAW*` pixel-format
/// flags (the astro path prefers the deepest available, falling back to 8-bit).
#[cfg(not(feature = "simulation"))]
fn bit_depth_from_flag(flag: u64) -> u32 {
    let has = |f: u32| flag & u64::from(f) != 0;
    if has(sys::TOUPCAM_FLAG_RAW16) {
        16
    } else if has(sys::TOUPCAM_FLAG_RAW14) {
        14
    } else if has(sys::TOUPCAM_FLAG_RAW12) {
        12
    } else if has(sys::TOUPCAM_FLAG_RAW10) {
        10
    } else {
        8
    }
}

#[cfg(feature = "simulation")]
pub mod simulation {
    //! Hardware-free, in-Rust simulation helpers (no SDK calls).
    use rand::RngExt;

    /// One 16-bit noise sample â€” a placeholder for a simulated sensor pixel.
    #[must_use]
    pub fn noise_sample() -> u16 {
        rand::rng().random()
    }

    /// Fill `buf` with simulated sensor noise as fast as possible.
    ///
    /// A seeded xorshift64 (a few integer ops per 8 bytes) â€” fast even in debug
    /// builds and single-core, so it cannot trip ConformU's 10 s `StartExposure`
    /// timeout the way a per-byte RNG or a core-grabbing parallel fill can. This
    /// is placeholder sensor noise, seeded per frame so frames differ
    /// run-to-run; quality is irrelevant. (Lesson carried from zwo-rs.)
    pub fn fill_noise(buf: &mut [u8]) {
        let mut state = rand::rng().random::<u64>() | 1;
        for chunk in buf.chunks_mut(8) {
            state ^= state << 13;
            state ^= state >> 7;
            state ^= state << 17;
            chunk.copy_from_slice(&state.to_le_bytes()[..chunk.len()]);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn sdk_new_succeeds() {
        Sdk::new().unwrap();
    }

    #[test]
    fn enumeration_returns_a_count() {
        let sdk = Sdk::new().unwrap();
        let count = sdk.camera_count().unwrap();
        #[cfg(feature = "simulation")]
        assert_eq!(count, SIM_CAMERA_COUNT);
        // Without the simulation feature this calls the real SDK; with no hardware
        // attached the count is zero, but the call must not panic.
        #[cfg(not(feature = "simulation"))]
        let _ = count;
    }

    #[test]
    fn hr_check_treats_nonnegative_as_success() {
        hr_check(0).unwrap(); // S_OK
        hr_check(1).unwrap(); // S_FALSE is also success
    }

    #[test]
    fn hr_check_maps_known_and_unknown_failures() {
        assert_eq!(
            hr_check(0x8000_4001_u32 as i32).unwrap_err(),
            Error::Sdk(SdkError::NotImplemented)
        );
        assert_eq!(
            hr_check(0x8007_0057_u32 as i32).unwrap_err(),
            Error::Sdk(SdkError::InvalidArg)
        );
        match hr_check(0x8000_1234_u32 as i32).unwrap_err() {
            Error::Sdk(SdkError::Unknown(_)) => {}
            other => panic!("expected Unknown, got {other:?}"),
        }
    }

    #[cfg(feature = "simulation")]
    #[test]
    fn simulation_fill_noise_fills_buffer() {
        let mut buf = vec![0u8; 4096];
        simulation::fill_noise(&mut buf);
        assert!(buf.iter().any(|&b| b != 0));
    }

    #[cfg(feature = "simulation")]
    #[test]
    fn simulation_noise_sample_runs() {
        let _ = simulation::noise_sample();
    }
}
